Consider the following C program:

#include <stdio.h>
#define EOF -1
void push(int);   /* push the argument on the stack */
int pop(void);    /* pop the top of the stack */
void flagError();

int main() {
    int c, m, n, r;
    while ((c = getchar()) != EOF) {
        if (isdigit(c))
            push(c);
        else if ((c == '+') || (c == '*')) {
            m = pop();
            n = pop();
            r = (c == '+') ? m + n : m * n;
            push(r);
        } else if (c != ' ')
            flagError();
    }
    printf("%d\n", pop());
}

What is the output of the above program for the following input?
2 + 3 . 3 . 2 + *

